int quickpow(int a,int b)
{
	int ans=1;
	wh(b)
	{
		if(b&1)ans=ans*a;
        a=a*a;
		b>>=1;
	}
	return ans;
}
CI MAXN=1e5+5;
int st[MAXN][25],n,m; 
signed main(void)
{

    //freopen(".in","r",stdin);
    //freopen(".out","w",stdout);
	IOS
	cin>>n>>m;
	FOR(i,1,n)
	{
		cin>>st[i][0];
	}
	for(int i=1;(1<<i)<=n;++i)
	{
		for(int j=1;j+(1<<i)-1<=n;++j)
		{
			st[j][i]=max(st[j][i-1],st[j+(1<<(i-1))][i-1]);
		}
	}
	FOR(i,1,m)
	{
		int l,r;
		cin>>l>>r;
		int k=log2(r-l+1);
		cout<<max(st[l][k],st[r-(1<<(k))+1][k])<<'\n';	
	}
